import logging
import os

logger = logging.getLogger(__name__)

class ParseError(Exception):
    pass

def parse_exchange_file(path, default_compartment):
    # Determine format based on extension or content
    _, ext = os.path.splitext(path.lower())
    if ext in ['.tsv', '.txt']:
        fmt = 'tsv'
    elif ext in ['.yaml', '.yml']:
        fmt = 'yaml'
    else:
        # Content-based detection
        with open(path, 'r', encoding='utf-8-sig') as f:
            first_line = None
            for line in f:
                stripped = line.strip()
                if stripped and not stripped.startswith('#'):
                    first_line = stripped
                    break
            if first_line is None:
                # Empty or only comments
                return
            # Check if first data line looks like TSV or YAML
            if '\t' in first_line:
                fmt = 'tsv'
            elif ':' in first_line:
                fmt = 'yaml'
            else:
                raise ParseError('Unable to detect format of exchange file {}'.format(path))

    if fmt == 'tsv':
        with open(path, 'r', encoding='utf-8-sig') as f:
            # Skip header line
            f.readline()
            for line in f:
                stripped = line.strip()
                if not stripped or stripped.startswith('#'):
                    continue
                parts = stripped.split('\t')
                if len(parts) != 3:
                    continue
                compound = parts[0]
                if not compound.isalnum():
                    continue
                try:
                    lower = float(parts[1])
                    upper = float(parts[2])
                except ValueError:
                    continue
                if lower > upper:
                    continue
                yield {'compound': compound, 'lower': lower, 'upper': upper}
    elif fmt == 'yaml':
        with open(path, 'r', encoding='utf-8-sig') as f:
            for line in f:
                stripped = line.strip()
                if not stripped or stripped.startswith('#'):
                    continue
                parts = stripped.split(':')
                if len(parts) < 3:
                    continue
                compound = parts[0]
                if not compound.isalnum():
                    continue
                try:
                    lower = float(parts[1])
                    upper = float(parts[2])
                except ValueError:
                    continue
                if lower > upper:
                    continue
                compartment = parts[3] if len(parts) > 3 else default_compartment
                yield {'compound': compound, 'lower': lower, 'upper': upper, 'compartment': compartment}
    else:
        raise ParseError('Unknown format')
